export const fetchRawReleases = cachedFunction(async (): Promise<RawRelease[]> => {
  const results = await Promise.allSettled(
    CHANGELOG_REPOS.map(async (repo) => {
      const { releases } = await $fetch<{ releases: UnghRelease[] }>(`https://ungh.cc/repos/${repo}/releases`)
      return releases
        .filter(r => !r.draft)
        .map(r => ({
          repo,
          tag: r.tag,
          title: r.name || r.tag,
          date: r.publishedAt,
          url: `https://github.com/${repo}/releases/tag/${r.tag}`,
          markdown: r.markdown
        }))
    })
  )

  return results
    .filter((r): r is PromiseFulfilledResult<RawRelease[]> => r.status === 'fulfilled')
    .flatMap(r => r.value)
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
}, {
  name: 'raw-releases',
  swr: true,
  maxAge: 60 * 60
})

if (
  (process.env.NUXT_OAUTH_FACEBOOK_CLIENT_ID && process.env.NUXT_OAUTH_FACEBOOK_CLIENT_SECRET)
  || (process.env.NUXT_OAUTH_INSTAGRAM_CLIENT_ID && process.env.NUXT_OAUTH_INSTAGRAM_CLIENT_SECRET)
) {
  // In facebook and instagram login, the url is redirected to /#_=_ which is not a valid route
  // so we remove it from the url, we are loading this long before the app is loaded
  // by using render:html hook
  // this is a hack, but it works
  // https://stackoverflow.com/questions/7131909/facebook-callback-appends-to-return-url
  nitroApp.hooks.hook('render:html', (html: NuxtRenderHTMLContext) => {
    html.head.unshift(`
    <script>
      if (window.location.hash === "#_=_"){
        history.replaceState
            ? history.replaceState(null, null, window.location.href.split("#")[0])
            : window.location.hash = "";
      }
    </script>
  `)
  })
}

if (!iframe) {
  const runtimeConfig = useRuntimeConfig()
  const CLIENT_BASE = '/__nuxt_devtools__/client'
  const CLIENT_PATH = `${runtimeConfig.app.baseURL.replace(CLIENT_BASE, '/')}${CLIENT_BASE}`.replace(MULTIPLE_SLASHES_RE, '/')
  const initialUrl = CLIENT_PATH + state.value.route
  iframe = document.createElement('iframe')

  // custom iframe props
  for (const [key, value] of Object.entries(runtimeConfig.app.devtools?.iframeProps || {}))
    iframe.setAttribute(key, String(value))

  iframe.id = 'nuxt-devtools-iframe'
  iframe.src = initialUrl
  iframe.onload = async () => {
    try {
      setIframeServerContext(iframe!)
      await waitForClientInjection()
      client.syncClient()
    }
    catch (e) {
      console.error('Nuxt DevTools client injection failed')
      console.error(e)
    }
  }
}

return {
    async enableTimeline(dry: boolean) {
      const filepath = nuxt.options._nuxtConfigFile
      const source = await fs.readFile(filepath, 'utf-8')
      const generated = await magicastGuard(async () => {
        const mod = parseModule(source, { sourceFileName: filepath })

        const options = getDefaultExportOptions(mod)

        options.devtools = options.devtools || {}
        options.devtools.timeline = options.devtools.timeline || {}
        options.devtools.timeline.enabled = true

        return mod.generate().code
      }, '\nYou can enable timeline manually by adding `devtools: { timeline: { enabled: true } }`')

      if (!dry) {
        await fs.writeFile(filepath, generated, 'utf-8')
        await nuxt.callHook('restart', { hard: true })
      }

      return [source, generated]
    },
  } satisfies Partial<ServerFunctions>

nitro.hooks.hook('render:response', async (response, { event }) => {
  if (typeof response.body === 'string' && (response.headers?.['Content-Type'] || response.headers?.['content-type'])?.includes('html')) {
    const formattedBody = await format(response.body, { plugins: [html], parser: 'html' })
    const results = await validator.validateString(formattedBody)

    if (response.body && results.errorCount > 0) {
      const id = randomUUID()
      const data: HtmlValidateReport = {
        id,
        path: event.path,
        html: formattedBody,
        results: results.results,
      }
      response.body = addBeforeBodyEndTag(
        response.body,
        `<script id="hints-html-validate" type="application/json">${stringify(data)}</script>`,
      )
      nitro.hooks.callHook(HTML_VALIDATE_REPORT_HOOK, data).catch((error) => {
        nitro.captureError(error instanceof Error ? error : new Error(String(error)), { event })
      })
    }
  }
})

if (nuxt.options.dev && !process.env[envSessionPassword]) {
  // If the password is set in the runtime config, use it
  if (nuxt.options.runtimeConfig.session.password) {
    process.env[envSessionPassword] = nuxt.options.runtimeConfig.session.password
  }
  else {
    const password = process.env[envSessionPassword] = randomUUID().replace(/-/g, '')
    // Add it to .env
    const envPath = join(nuxt.options.rootDir, '.env')
    const envContent = await readFile(envPath, 'utf-8').catch(() => '')
    if (!envContent.includes(envSessionPassword)) {
      await writeFile(
        envPath,
        `${
          envContent ? envContent + '\n' : envContent
        }${envSessionPassword}=${password}`,
        'utf-8',
      )
    }
  }
}

const CookieDefaults = {
  path: '/',
  watch: true,
  decode: val => val ? parseCookieValue(decodeURIComponent(val)) : val,
  encode: (val) => {
    // JSON-quote strings that would be coerced on decode (e.g. '42', 'true', 'null', 'undefined')
    if (typeof val !== 'string' || val === 'undefined') {
      return encodeURIComponent(JSON.stringify(val))
    }

    try {
      if (typeof JSON.parse(val) !== 'string') {
        return encodeURIComponent(JSON.stringify(val))
      }
    } catch {
      // ignore - value is not JSON, so encode as-is
    }
    return encodeURIComponent(val)
  },
  refresh: false,
} satisfies CookieOptions<any>

