const iterator: AsyncIterableIterator<WideEvent> = {
  [Symbol.asyncIterator]() {
    return iterator
  },
  next(): Promise<IteratorResult<WideEvent>> {
    if (queue.length > 0) {
      return Promise.resolve({ value: queue.shift()!, done: false })
    }
    if (closed) {
      return Promise.resolve({ value: undefined, done: true })
    }
    return new Promise((resolve) => {
      pendingResolve = resolve
    })
  },
  return(): Promise<IteratorResult<WideEvent>> {
    closed = true
    asyncSubscribers.delete(subscriber)
    if (pendingResolve) {
      const resolve = pendingResolve
      pendingResolve = null
      resolve({ value: undefined, done: true })
    }
    return Promise.resolve({ value: undefined, done: true })
  },
}

onMounted(() => {
  prefersReducedMotion.value = window.matchMedia('(prefers-reduced-motion: reduce)').matches
  if (prefersReducedMotion.value) {
    revealed.value = rows.map(() => true)
    tampered.value = true
    linkState.value = rows.map((_, i) => {
      if (i < TAMPERED_INDEX) return 'ok'
      if (i === TAMPERED_INDEX) return 'broken'
      return 'invalid'
    })
    status.value = 'tampered'
    return
  }
  if (!wrapperRef.value) {
    start()
    return
  }
  observer = new IntersectionObserver(
    ([entry]) => {
      if (entry?.isIntersecting) {
        start()
        observer?.disconnect()
      }
    },
    { threshold: 0.25 },
  )
  observer.observe(wrapperRef.value)
})

watchDebounced([routeInputs, activeTab], () => {
  const savedEntry = savedRouteInputs.value?.find(entry => entry.task === props.task.name)

  if (!savedEntry) {
    const newEntry = {
      task: props.task.name,
      tab: 'query',
      inputs: routeInputs,
    }
    savedRouteInputs.value.push(newEntry)

    if (!activeTab.value)
      activeTab.value = newEntry.tab
  }
  else {
    if (!activeTab.value)
      activeTab.value = savedEntry.tab

    if (savedEntry.tab !== activeTab.value)
      savedEntry.tab = activeTab.value

    //  update routeInputs with local storage
    const { body, query, headers } = savedEntry.inputs
    Object.assign(routeInputs, { body, query, headers })
  }
}, { immediate: true, deep: true, debounce: 500 })
